import React, { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import { AuthContext } from '../context/AuthContext';

const BookAppointment = () => {
  const { user } = useContext(AuthContext);

  const [formData, setFormData] = useState({
    doctor: '',
    date: '',
    time: '',
  });

  const [doctors, setDoctors] = useState([]);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');


  useEffect(() => {
    const fetchDoctors = async () => {
      try {
        const res = await axios.get('/api/user/doctors', { withCredentials: true });
        setDoctors(res.data);
      } catch (err) {
        console.error('Error fetching doctors:', err);
        setError('Failed to load doctors.');
      }
    };

    if (user?.role === 'User' || user?.role === 'Admin') {
      fetchDoctors();
    }
  }, [user]);

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');

    if (!user) {
      setError('You must be logged in to book an appointment.');
      return;
    }

    try {
      const appointmentDate = new Date(`${formData.date}T${formData.time}:00`);

      await axios.post(
          '/api/bookings',
          {
            doctor: formData.doctor,
            appointmentDate,
          },
          { withCredentials: true }
      );

      setMessage(' Appointment booked successfully!');
      setFormData({ doctor: '', date: '', time: '' });
    } catch (err) {
      setError(err.response?.data?.message || ' Failed to book appointment.');
    }
  };

  // ✅ Conditional return AFTER hooks
  if (user?.role === 'Doctor') {
    return (
        <div className="text-red-600 text-center mt-10">
          Access Denied: Doctors are not allowed to book appointments.
        </div>
    );
  }

  return (
      <div className="max-w-xl mx-auto mt-16 bg-white shadow-lg p-6 rounded-lg">
        <h1 className="text-2xl font-bold mb-4 text-center text-blue-700">Book Appointment</h1>

        {message && <p className="text-green-600 text-center mb-3">{message}</p>}
        {error && <p className="text-red-600 text-center mb-3">{error}</p>}

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block mb-1 font-medium text-gray-700">Select Doctor</label>
            <select
                name="doctor"
                value={formData.doctor}
                onChange={handleChange}
                required
                className="w-full px-4 py-2 border border-gray-300 rounded"
            >
              <option value="">-- Select Doctor --</option>
              {doctors.map((doc) => (
                  <option key={doc._id} value={doc._id}>
                    Dr. {doc.username}
                  </option>
              ))}
            </select>
          </div>

          <div>
            <label className="block mb-1 font-medium text-gray-700">Date</label>
            <input
                type="date"
                name="date"
                value={formData.date}
                onChange={handleChange}
                required
                className="w-full px-4 py-2 border border-gray-300 rounded"
            />
          </div>

          <div>
            <label className="block mb-1 font-medium text-gray-700">Time</label>
            <input
                type="time"
                name="time"
                value={formData.time}
                onChange={handleChange}
                required
                className="w-full px-4 py-2 border border-gray-300 rounded"
            />
          </div>

          <button
              type="submit"
              className="w-full bg-blue-600 hover:bg-blue-700 text-white py-2 rounded transition"
          >
            Book Now
          </button>
        </form>
      </div>
  );
};

export default BookAppointment;
